// Pull the grant-seeker profile's search dimensions out of the TTL.
// Looks for p:focus-area / p:geography / p:funding-need literals.
const ttl = $input.first().json.data ?? $input.first().json.body ?? $json.data ?? '';
const grab = (pred) => [...String(ttl).matchAll(new RegExp('p:' + pred + '\\s+"([^"]+)"', 'g'))].map(m => m[1]);
const focus = grab('focus-area');
const geography = grab('geography');
const fundingNeed = grab('funding-need');
// Build a keyword string for the Grants.gov search.
const keyword = [...focus, ...fundingNeed].join(' ') || 'community nonprofit';
return [{ json: { focus, geography, fundingNeed, keyword } }];

// Map each opportunity to a Reckons.AI pending.jsonl line.
// Shape (drainWorkspacePending): { subject, predicate, object, note?, type?, agent?, priority? }
const res = $input.first().json;
const list = res.oppHits ?? res.opportunities ?? res.data ?? [];
const geography = ($('Profile → search query').first().json.geography ?? []).map(s => s.toLowerCase());
const lines = [];
for (const o of list) {
  const id = o.id ?? o.oppNumber ?? o.number ?? Math.random().toString(36).slice(2);
  const title = o.title ?? o.oppTitle ?? 'Untitled call';
  const agency = o.agency ?? o.agencyName ?? '';
  const close = o.closeDate ?? o.oppCloseDate ?? '';
  const subj = `urn:kbase:concept/grant-call/${String(id).replace(/[^A-Za-z0-9_-]/g, '-')}`;
  const add = (predicate, object, note) => lines.push(JSON.stringify({ subject: subj, predicate, object, note, type: 'suggestion', agent: 'n8n-grant-scrape', priority: 'normal' }));
  add('http://www.w3.org/2000/01/rdf-schema#label', title, `From Grants.gov — ${agency}`);
  add('urn:kbase:predicate/matches', 'urn:kbase:concept/your-profile', 'auto-matched by scrape — confirm eligibility');
  if (close) add('urn:kbase:predicate/deadline', String(close));
  if (agency) add('urn:kbase:predicate/funder', agency);
  add('urn:kbase:predicate/link', o.url ?? `https://www.grants.gov/search-results-detail/${id}`);
  // Growing-filter question: ask for anything the profile likely can't answer yet.
  lines.push(JSON.stringify({ subject: 'urn:kbase:concept/your-profile', predicate: 'urn:kbase:predicate/annual-budget', note: `Required by "${title}" — what is your annual operating budget?`, type: 'question', agent: 'n8n-grant-scrape', priority: 'normal' }));
}
return [{ json: { jsonl: lines.join('\n') + (lines.length ? '\n' : ''), count: lines.length } }];
